+  // Transform patterns where a select condition is another select with a constant arm,
+  // and the corresponding arm of the outer select is also a select with the same condition.
+  // 1. select (select C, X, false), Y, (select C, A, B) -> select C, (select X, Y, A), B
+  // 2. select (select C, true, X), (select C, A, B), Y -> select C, A, (select X, B, Y)
+  if (SelectInst *CondSI = dyn_cast<SelectInst>(CondVal)) {
+    Value *C, *X;
+    Constant *Const;
+    // Match select C, X, Const or select C, Const, X
+    // Determine which arm corresponds to constant.
+    bool ConstIsTrue = false;
+    Value *Other = nullptr;
+    if (match(CondSI, m_Select(m_Value(C), m_Value(X), m_Constant(Const)))) {
+      // constant on false side
+      ConstIsTrue = Const->isOneValue();
+      Other = X;
+    } else if (match(CondSI, m_Select(m_Value(C), m_Constant(Const), m_Value(X)))) {
+      // constant on true side
+      ConstIsTrue = Const->isOneValue();
+      Other = X;
+    } else {
+      // no constant, skip
+      Const = nullptr;
+    }
+    if (Const && (Const->isZeroValue() || Const->isOneValue())) {
+      // Determine which arm of outer select corresponds to constant branch.
+      SelectInst *ArmSI = nullptr;
+      if (ConstIsTrue) {
+        // When constant is true, outer condition is true when C true, so outer true value is selected.
+        // That arm must be a select with same condition C.
+        ArmSI = dyn_cast<SelectInst>(TrueVal);
+      } else {
+        // When constant is false, outer condition is false when C false, so outer false value is selected.
+        ArmSI = dyn_cast<SelectInst>(FalseVal);
+      }
+      if (ArmSI) {
+        Value *C2, *A, *B;
+        if (match(ArmSI, m_Select(m_Value(C2), m_Value(A), m_Value(B))) && C == C2) {
+          // Transform.
+          if (ConstIsTrue) {
+            // select (select C, true, X), (select C, A, B), Y -> select C, A, (select X, B, Y)
+            // where Y is the other outer arm (FalseVal).
+            Value *InnerSelect = Builder.CreateSelect(Other, B, FalseVal);
+            Value *NewOuter = Builder.CreateSelect(C, A, InnerSelect);
+            return replaceInstUsesWith(SI, NewOuter);
+          } else {
+            // select (select C, X, false), Y, (select C, A, B) -> select C, (select X, Y, A), B
+            Value *InnerSelect = Builder.CreateSelect(Other, TrueVal, A);
+            Value *NewOuter = Builder.CreateSelect(C, InnerSelect, B);
+            return replaceInstUsesWith(SI, NewOuter);
+          }
+        }
+      }
+    }
+  }

